+                        ) {
+                            Ok(()) => {
+                                inodes_clean += 1;
+                                passed += 1;
+                            }
+                            Err(e) => {
+                                verdicts.push(CheckVerdict {
+                                    component: format!("inode[{ino}]"),
+                                    passed: false,
+                                    detail: e.to_string(),
+                                });
+                                inodes_corrupt += 1;
+                                failed += 1;
+                            }
+                        }
+                    }
+                }
